	Where MrkTip = TipoMarketplace.MercadoLivre
	Where MrkStsInt = StatusMarketplace.Integrada
	Where MrkSts = Status_AtivoInativo.ATIVO
	prcMercadolivreRefreshToken.Call(EmpCod, MrkCod, &MrkSession, &IsSucesso)
	Exit
EndFor

